      const value = arg.slice(equalsIndex + 1)
      result[key] = value
      continue
    }

    const next = argv[i + 1]
    const isNextValue = next && !next.startsWith('-')

    if (isNextValue) {
      result[arg.slice(2)] = next
      i++
    } else {
      result[arg.slice(2)] = true
    }
  }

  return result
}

